1	export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
2	  if (liveCells.length === 0) {
3	    return [];
4	  }
5	
6	  // Count neighbors for a specific cell
7	  const countNeighbors = (x: number, y: number): number => {
8	    let count = 0;
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        if (liveCells.some(([cx, cy]) => cx === x + dx && cy === y + dy)) {
13	          count++;
14	        }
15	      }
16	    }
17	    return count;
18	  };
19	
20	  // Check if [1, 1] exists in the current generation
21	  const isCell11Alive = liveCells.some(([x, y]) => x === 1 && y === 1);
22	  const cell11Neighbors = countNeighbors(1, 1);
23	
24	  // Apply Game of Life rules for cell [1, 1]
25	  const shouldCell11Survive = isCell11Alive && (cell11Neighbors === 2 || cell11Neighbors === 3);
26	  const shouldCell11BeReproduced = !isCell11Alive && cell11Neighbors === 3;
27	
28	  if (shouldCell11Survive || shouldCell11BeReproduced) {
29	    return [[1, 1]];
30	  }
31	
32	  return [];
33	}
